--- celtic2_gpu.frag
001: #include <flutter/runtime_effect.glsl>
002: 
003: precision highp float;
004: 
005: // Celtic²: z_{n+1} = |Re(z²)|+Im(z²) + c.
006: // Mandelbrot analogue — pixel = c, z₀ = 0.
007: // The Celtic fold applies absolute value only to Re(z²) = x²−y² after
008: // the squaring, leaving Im(z²) = 2xy unchanged. This one-sided fold
009: // creates a 2-armed fractal with bilateral symmetry about the imaginary
010: // axis. The reflected real part produces a characteristic pinched-waist
011: // shape with inward-curved cusp boundaries distinct from the Mandelbrot set.
012: // Smooth coloring: log₂(2) = 1. Supports normal-map shading (colorScheme 50-63).
013: uniform float uTime;
014: uniform vec2  uResolution;
015: uniform vec2  uCenter;
016: uniform float uZoom;
017: uniform float uIterations;
018: uniform float uBailout;
019: uniform float uColorScheme;
020: uniform float uTransparentBg;
021: 
022: out vec4 fragColor;
023: 
024: vec3 linearToSRGB(vec3 lin) {
025:   lin = clamp(lin, 0.0, 1.0);
026:   bvec3 cutoff = lessThan(lin, vec3(0.0031308));
027:   vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
028:   vec3 lo = lin * 12.92;
029:   return mix(hi, lo, vec3(cutoff));
030: }
031: 
032: vec3 palette(float t, int scheme) {
033:   if (scheme == 0) return vec3(0.5+0.5*cos(6.28318*(t+0.0)), 0.5+0.5*cos(6.28318*(t+0.4)), 0.5+0.5*cos(6.28318*(t+0.7)));
034:   if (scheme == 1) return vec3(0.5+0.5*cos(6.28318*(t+0.5)), 0.5+0.5*cos(6.28318*(t+0.3)), 0.5+0.5*cos(6.28318*(t+0.0)));
035:   if (scheme == 2) return vec3(0.5+0.5*cos(6.28318*(t+0.0)), 0.5+0.5*cos(6.28318*(t+0.33)), 0.5+0.5*cos(6.28318*(t+0.67)));
036:   if (scheme == 3) { float g = 0.5+0.5*cos(6.28318*t); return vec3(g); }
037:   float s = float(scheme);
038:   vec3 a = 0.55+0.15*sin(vec3(1.0,2.0,3.0)*(0.37*s+0.1));
039:   vec3 b = 0.45+0.25*cos(vec3(1.7,2.3,2.9)*(0.29*s+0.2));
040:   vec3 c4 = 1.0+0.80*sin(vec3(0.8,1.3,1.7)*(0.11*s+0.3));
041:   vec3 d = fract(sin(vec3(12.9898,78.233,37.719)*(s+0.5))*43758.5453);
042:   return clamp(a+b*cos(6.28318*(c4*t+d)),0.0,1.0);
043: }
044: 
045: vec2 cmul(vec2 a, vec2 b) { return vec2(a.x*b.x-a.y*b.y, a.x*b.y+a.y*b.x); }
046: 
047: void main() {
048:   vec2 fragCoord = FlutterFragCoord().xy;
049:   float scale = min(uResolution.x, uResolution.y);
050:   vec2 uv = (fragCoord - 0.5*uResolution) / max(1.0, scale);
051: 
052:   int schemeInt = int(uColorScheme);
053:   vec2 c   = uv / max(0.000001, uZoom) + uCenter;
054:   vec2 z   = vec2(0.0);
055:   vec2 der = vec2(0.0);
056: 
057:   float bailoutSq = uBailout * uBailout;
058:   const int MAX_ITERS = 500;
059:   int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
060:   int it = 0;
061: 
062:   for (int j = 0; j < MAX_ITERS; j++) {
063:     if (j >= target) { it = target; break; }
064:     vec2 z2 = cmul(z, z);
065:     // Derivative: 2·z·der + 1 (Mandelbrot mode; fold approx.)
066:     der = 2.0 * cmul(z, der) + vec2(1.0, 0.0);
067:     // Celtic fold: |Re(z²)| + Im(z²)
068:     z = vec2(abs(z2.x), z2.y) + c;
069:     if (dot(z,z) > bailoutSq) { it = j; break; }
070:     it = j + 1;
071:   }
072: 
073:   if (it >= target) {
074:     fragColor = (uTransparentBg > 0.5) ? vec4(0.0) : vec4(0.0,0.0,0.0,1.0);
075:     return;
076:   }
077: 
078:   float mag2      = max(1e-12, dot(z, z));
079:   float smoothVal = float(it) - log2(log2(mag2));  // log2(2)=1, so no division needed
080: 
--- celtic_cubic_gpu.frag
001: #include <flutter/runtime_effect.glsl>
002: 
003: precision highp float;
004: 
005: // Celtic Cubic: z_{n+1} = |Re(z_n^3)| + i·Im(z_n^3) + c
006: // Extends Celtic to power 3 — abs applied to the real part of z^3 only.
007: // The 3-fold symmetry of z^3 combined with the Celtic abs-fold produces
008: // aperiodic structures richer than either parent fractal alone.
009: // Supports normal-map shading (colorScheme 50-63).
010: uniform float uTime;          // 0
011: uniform vec2  uResolution;    // 1-2
012: uniform vec2  uCenter;        // 3-4
013: uniform float uZoom;          // 5
014: uniform float uIterations;    // 6
015: uniform float uBailout;       // 7
016: uniform float uColorScheme;   // 8
017: uniform float uTransparentBg; // 9
018: 
019: out vec4 fragColor;
020: 
021: vec3 linearToSRGB(vec3 lin) {
022:   lin = clamp(lin, 0.0, 1.0);
023:   bvec3 cutoff = lessThan(lin, vec3(0.0031308));
024:   vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
025:   vec3 lo = lin * 12.92;
026:   return mix(hi, lo, vec3(cutoff));
027: }
028: 
029: // colorScheme 0-49: standard palette coloring.
030: // colorScheme 50-63: normal-map (bas-relief) mode — 14 light angles × 4 base palettes.
031: vec3 palette(float t, int scheme) {
032:   if (scheme == 0) {
033:     return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.4)),0.5+0.5*cos(6.28318*(t+0.7)));
034:   } else if (scheme == 1) {
035:     return vec3(0.5+0.5*cos(6.28318*(t+0.5)),0.5+0.5*cos(6.28318*(t+0.3)),0.5+0.5*cos(6.28318*(t+0.0)));
036:   } else if (scheme == 2) {
037:     return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.33)),0.5+0.5*cos(6.28318*(t+0.67)));
038:   } else if (scheme == 3) {
039:     float g = 0.5+0.5*cos(6.28318*t); return vec3(g);
040:   }
041:   float s = float(scheme);
042:   vec3 a = 0.55 + 0.15 * sin(vec3(1.0,2.0,3.0) * (0.37*s+0.1));
043:   vec3 b = 0.45 + 0.25 * cos(vec3(1.7,2.3,2.9) * (0.29*s+0.2));
044:   vec3 c = 1.0  + 0.80 * sin(vec3(0.8,1.3,1.7) * (0.11*s+0.3));
045:   vec3 d = fract(sin(vec3(12.9898,78.233,37.719) * (s+0.5)) * 43758.5453);
046:   return clamp(a + b * cos(6.28318*(c*t+d)), 0.0, 1.0);
047: }
048: 
049: void main() {
050:   vec2 fragCoord = FlutterFragCoord().xy;
051:   float scale = min(uResolution.x, uResolution.y);
052:   vec2 uv = (fragCoord - 0.5*uResolution) / max(1.0, scale);
053: 
054:   int schemeInt = int(uColorScheme);
055:   vec2 c   = uv / max(0.000001, uZoom) + uCenter;
056:   vec2 z   = vec2(0.0);
057:   // Derivative dz/dc for normal-map shading.
058:   // d(Re(z^3))/dc = Re(3*z^2 * der)
059:   // d|Re(z^3)|/dc = sign(Re(z^3)) * d(Re(z^3))/dc
060:   vec2 der = vec2(0.0);
061: 
062:   float bailoutSq = uBailout * uBailout;
063:   const int MAX_ITERS = 500;
064:   int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
065:   int it = 0;
066: 
067:   for (int j = 0; j < MAX_ITERS; j++) {
068:     if (j >= target) { it = target; break; }
069: 
070:     // Celtic Cubic: z_{n+1} = |Re(z^3)| + i*Im(z^3) + c
071:     float x2 = z.x*z.x;
072:     float y2 = z.y*z.y;
073:     float x3 = z.x*(x2 - 3.0*y2);  // Re(z^3)
074:     float y3 = z.y*(3.0*x2 - y2);  // Im(z^3)
075: 
076:     // Derivative: d(z^3)/dc = 3*z^2*der, abs gate on Re only
077:     float z2r = x2 - y2;             // Re(z^2)
078:     float z2i = 2.0*z.x*z.y;        // Im(z^2)
079:     float dx3 = 3.0*(z2r*der.x - z2i*der.y);  // d(Re(z^3))/dc
080:     float dy3 = 3.0*(z2r*der.y + z2i*der.x);  // d(Im(z^3))/dc
--- celtic_cubic_julia_gpu.frag
001: #include <flutter/runtime_effect.glsl>
002: 
003: precision highp float;
004: 
005: // Celtic Cubic Julia set: z_{n+1} = |Re(z³)| + Im(z³) + c, c = (−0.32, 0.60).
006: // Julia set of the degree-3 Celtic map — pixel = z₀, c = (−0.32, 0.60) is fixed.
007: // The Celtic map folds only the real part of z³ through absolute value, leaving
008: // the imaginary part unfolded. At degree 3 this creates three-armed Julia sets
009: // with asymmetric left-right character: the right arms retain the smooth cusp
010: // boundary of z³ while the folded-real axis produces doubled lobes.
011: // Near c=(−0.32, 0.60) the set is connected with distinct trilateral structure.
012: // Derivative approximation: 3z²·der (Julia mode, ignores Re fold).
013: // Supports normal-map shading (colorScheme 50-63).
014: uniform float uTime;
015: uniform vec2  uResolution;
016: uniform vec2  uCenter;
017: uniform float uZoom;
018: uniform float uIterations;
019: uniform float uBailout;
020: uniform float uColorScheme;
021: uniform float uTransparentBg;
022: 
023: out vec4 fragColor;
024: 
025: vec3 linearToSRGB(vec3 lin) {
026:   lin = clamp(lin, 0.0, 1.0);
027:   bvec3 cutoff = lessThan(lin, vec3(0.0031308));
028:   vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
029:   vec3 lo = lin * 12.92;
030:   return mix(hi, lo, vec3(cutoff));
031: }
032: 
033: vec3 palette(float t, int scheme) {
034:   if (scheme == 0) return vec3(0.5+0.5*cos(6.28318*(t+0.0)), 0.5+0.5*cos(6.28318*(t+0.4)), 0.5+0.5*cos(6.28318*(t+0.7)));
035:   if (scheme == 1) return vec3(0.5+0.5*cos(6.28318*(t+0.5)), 0.5+0.5*cos(6.28318*(t+0.3)), 0.5+0.5*cos(6.28318*(t+0.0)));
036:   if (scheme == 2) return vec3(0.5+0.5*cos(6.28318*(t+0.0)), 0.5+0.5*cos(6.28318*(t+0.33)), 0.5+0.5*cos(6.28318*(t+0.67)));
037:   if (scheme == 3) { float g = 0.5+0.5*cos(6.28318*t); return vec3(g); }
038:   float s = float(scheme);
039:   vec3 a = 0.55+0.15*sin(vec3(1.0,2.0,3.0)*(0.37*s+0.1));
040:   vec3 b = 0.45+0.25*cos(vec3(1.7,2.3,2.9)*(0.29*s+0.2));
041:   vec3 c4 = 1.0+0.80*sin(vec3(0.8,1.3,1.7)*(0.11*s+0.3));
042:   vec3 d = fract(sin(vec3(12.9898,78.233,37.719)*(s+0.5))*43758.5453);
043:   return clamp(a+b*cos(6.28318*(c4*t+d)),0.0,1.0);
044: }
045: 
046: vec2 cmul(vec2 a, vec2 b) { return vec2(a.x*b.x-a.y*b.y, a.x*b.y+a.y*b.x); }
047: 
048: void main() {
049:   vec2 fragCoord = FlutterFragCoord().xy;
050:   float scale = min(uResolution.x, uResolution.y);
051:   vec2 uv = (fragCoord - 0.5*uResolution) / max(1.0, scale);
052: 
053:   int schemeInt = int(uColorScheme);
054:   vec2 z   = uv / max(0.000001, uZoom) + uCenter;
055:   vec2 c   = vec2(-0.32, 0.60);   // fixed Julia parameter
056:   vec2 der = vec2(1.0, 0.0);
057: 
058:   float bailoutSq = uBailout * uBailout;
059:   const int MAX_ITERS = 500;
060:   int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
061:   int it = 0;
062: 
063:   for (int j = 0; j < MAX_ITERS; j++) {
064:     if (j >= target) { it = target; break; }
065:     vec2 z2 = cmul(z, z);
066:     vec2 z3 = cmul(z2, z);
067:     // Derivative approximation: 3z²·der (Julia mode: no +1)
068:     der = 3.0 * cmul(z2, der);
069:     // Celtic cubic fold: |Re(z³)| + Im(z³)
070:     z = vec2(abs(z3.x), z3.y) + c;
071:     if (dot(z,z) > bailoutSq) { it = j; break; }
072:     it = j + 1;
073:   }
074: 
075:   if (it >= target) {
076:     fragColor = (uTransparentBg > 0.5) ? vec4(0.0) : vec4(0.0,0.0,0.0,1.0);
077:     return;
078:   }
079: 
080:   float mag2      = max(1e-12, dot(z, z));
