001: #include <flutter/runtime_effect.glsl>
002: 
003: precision highp float;
004: 
005: uniform float uTime;          // 0
006: uniform vec2  uResolution;    // 1-2
007: uniform vec2  uCenter;        // 3-4
008: uniform float uZoom;          // 5
009: uniform float uIterations;    // 6
010: uniform float uBailout;       // 7
011: uniform float uColorScheme;   // 8
012: uniform float uTransparentBg; // 9
013: 
014: out vec4 fragColor;
015: 
016: // IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
017: vec3 linearToSRGB(vec3 lin) {
018:   lin = clamp(lin, 0.0, 1.0);
019:   bvec3 cutoff = lessThan(lin, vec3(0.0031308));
020:   vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
021:   vec3 lo = lin * 12.92;
022:   return mix(hi, lo, vec3(cutoff));
023: }
024: 
025: // colorScheme 0-49: standard palette coloring.
026: // colorScheme 50-63: normal-map (bas-relief) mode — 14 light angles × 4 base palettes.
027: vec3 palette(float t, int scheme) {
028:   if (scheme == 0) {
029:     return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.4)),0.5+0.5*cos(6.28318*(t+0.7)));
030:   } else if (scheme == 1) {
031:     return vec3(0.5+0.5*cos(6.28318*(t+0.5)),0.5+0.5*cos(6.28318*(t+0.3)),0.5+0.5*cos(6.28318*(t+0.0)));
032:   } else if (scheme == 2) {
033:     return vec3(0.5+0.5*cos(6.28318*(t+0.0)),0.5+0.5*cos(6.28318*(t+0.33)),0.5+0.5*cos(6.28318*(t+0.67)));
034:   } else if (scheme == 3) {
035:     float g = 0.5+0.5*cos(6.28318*t); return vec3(g);
036:   }
037: 
038:   float s = float(scheme);
039:   vec3 a = 0.55 + 0.15 * sin(vec3(1.0, 2.0, 3.0) * (0.37 * s + 0.1));
040:   vec3 b = 0.45 + 0.25 * cos(vec3(1.7, 2.3, 2.9) * (0.29 * s + 0.2));
041:   vec3 c = 1.0  + 0.80 * sin(vec3(0.8, 1.3, 1.7) * (0.11 * s + 0.3));
042:   vec3 d = fract(sin(vec3(12.9898, 78.233, 37.719) * (s + 0.5)) * 43758.5453);
043:   vec3 col = a + b * cos(6.28318 * (c * t + d));
044:   return clamp(col, 0.0, 1.0);
045: }
046: 
047: void main() {
048:   vec2 fragCoord = FlutterFragCoord().xy;
049:   float scale = min(uResolution.x, uResolution.y);
050:   vec2 uv = (fragCoord - 0.5*uResolution) / max(1.0, scale);
051: 
052:   int schemeInt = int(uColorScheme);
053:   vec2 c   = uv / max(0.000001, uZoom) + uCenter;
054:   vec2 z   = vec2(0.0);
055:   // Complex derivative dz/dc for normal-map shading.
056:   // Celtic applies abs() to Re(z^2) only; chain rule:
057:   //   d|Re(z^2)|/dc = sign(Re(z^2)) * d(Re(z^2))/dc = sign(x2) * Re(2*z*der)
058:   //   d(Im(z^2))/dc = Im(2*z*der)
059:   vec2 der = vec2(0.0);
060: 
061:   float bailoutSq = uBailout * uBailout;
062:   const int MAX_ITERS = 500;
063:   int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
064:   int it = 0;
065: 
066:   for (int j = 0; j < MAX_ITERS; j++) {
067:     if (j >= target) { it = target; break; }
068: 
069:     // Celtic: z_{n+1} = (|Re(z_n^2)| + i*Im(z_n^2)) + c
070:     float x2 = z.x*z.x - z.y*z.y;
071:     float y2 = 2.0*z.x*z.y;
072:     // Derivative update: abs gate only on real component of z^2
073:     float dx2 = 2.0*(z.x*der.x - z.y*der.y);  // d(Re(z^2))/dc
074:     float dy2 = 2.0*(z.x*der.y + z.y*der.x);  // d(Im(z^2))/dc
075:     der = vec2(sign(x2) * dx2 + 1.0, dy2);
076:     z = vec2(abs(x2) + c.x, y2 + c.y);
077: 
078:     if (dot(z, z) > bailoutSq) { it = j; break; }
079:     it = j + 1;
080:   }
--- celtic_julia_gpu.frag
001: #include <flutter/runtime_effect.glsl>
002: 
003: precision highp float;
004: 
005: uniform float uTime;
006: uniform vec2  uResolution;
007: uniform vec2  uCenter;
008: uniform float uZoom;
009: uniform float uIterations;
010: uniform float uBailout;
011: uniform float uColorScheme;
012: uniform float uTransparentBg;
013: 
014: out vec4 fragColor;
015: 
016: // IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
017: vec3 linearToSRGB(vec3 lin) {
018:   lin = clamp(lin, 0.0, 1.0);
019:   bvec3 cutoff = lessThan(lin, vec3(0.0031308));
020:   vec3 hi = 1.055 * pow(max(lin, vec3(0.0031308)), vec3(1.0 / 2.4)) - 0.055;
021:   vec3 lo = lin * 12.92;
022:   return mix(hi, lo, vec3(cutoff));
023: }
024: 
025: const int MAX_ITERS = 500;
026: 
027: vec3 iqPalette(float t, vec3 a, vec3 b, vec3 c, vec3 d) {
028:   return a + b * cos(6.28318 * (c * t + d));
029: }
030: 
031: vec3 getPaletteColor(float t, int scheme) {
032:   t = fract(t);
033:   if (scheme == 0) return iqPalette(t, vec3(0.5), vec3(0.5), vec3(1.0), vec3(0.0,0.33,0.67));
034:   if (scheme == 1) return iqPalette(t, vec3(0.5), vec3(0.5), vec3(1.0), vec3(0.0,0.10,0.20));
035:   if (scheme == 2) return iqPalette(t, vec3(0.5), vec3(0.5), vec3(1.0,0.7,0.4), vec3(0.0,0.15,0.20));
036:   if (scheme == 3) return iqPalette(t, vec3(0.5), vec3(0.5), vec3(1.0), vec3(0.0));
037:   float s = float(scheme);
038:   vec3 a = vec3(0.5 + 0.2*sin(s*1.1), 0.5 + 0.2*sin(s*1.3), 0.5 + 0.2*sin(s*1.7));
039:   vec3 b = vec3(0.5 + 0.3*cos(s*0.7), 0.5 + 0.3*cos(s*1.1), 0.5 + 0.3*cos(s*0.3));
040:   vec3 c = vec3(1.0 + sin(s*0.5), 1.0 + sin(s*0.9), 1.0 + sin(s*1.3));
041:   vec3 d = vec3(fract(s*0.13), fract(s*0.17), fract(s*0.23));
042:   return clamp(iqPalette(t, a, b, c, d), 0.0, 1.0);
043: }
044: 
045: vec2 cmul(vec2 a, vec2 b) { return vec2(a.x*b.x - a.y*b.y, a.x*b.y + a.y*b.x); }
046: vec2 cadd(vec2 a, vec2 b) { return a + b; }
047: vec2 csub(vec2 a, vec2 b) { return a - b; }
048: vec2 cconj(vec2 z) { return vec2(z.x, -z.y); }
049: vec2 cdiv(vec2 a, vec2 b) {
050:   float d = max(dot(b,b), 1e-12);
051:   return vec2(a.x*b.x + a.y*b.y, a.y*b.x - a.x*b.y) / d;
052: }
053: vec2 cpow2(vec2 z) { return cmul(z,z); }
054: vec2 cpow3(vec2 z) { return cmul(cpow2(z), z); }
055: vec2 cexp(vec2 z) {
056:   float ex = exp(clamp(z.x, -40.0, 40.0));
057:   return ex * vec2(cos(z.y), sin(z.y));
058: }
059: vec2 csin(vec2 z) {
060:   float y = clamp(z.y, -20.0, 20.0);
061:   return vec2(sin(z.x)*cosh(y), cos(z.x)*sinh(y));
